(function(){var ranks=['pop-rank-1','pop-rank-2','pop-rank-3'];var items=document.querySelectorAll('.pop-item-wrap');var petalColors2=['#bfdbfe','#93c5fd','#ddd6fe','#c4b5fd','#e0f2fe'];var petalColors3=['#fca5a5','#fda4af','#fcd34d','#fdba74','#fde68a'];items.forEach(function(el,i){var num=el.querySelector('.pop-rank-num');if(!num)return;num.textContent='';var span=document.createElement('span');span.className='shimmer-num';span.textContent=i+1;num.appendChild(span);num.className='pop-rank-num '+(ranks[i]||'pop-rank-other');el.style.setProperty('--shimmer-delay',i*0.5);if(i===1||i===2){var colors=i===1?petalColors2:petalColors3;for(var p=0;p<7;p++){var petal=document.createElement('span');petal.className='pop-petal';var size=7+Math.random()*6;petal.style.cssText=['left:'+(8+Math.random()*84)+'%','top:-'+(10+Math.random()*15)+'px','width:'+size+'px','height:'+(size*0.65)+'px','background:'+colors[p%colors.length],'animation-duration:'+(2.2+Math.random()*2.5)+'s','animation-delay:'+(Math.random()*3)+'s','transform:rotate('+(Math.random()*360)+'deg)','border-radius:70% 30% 70% 30%'].join(';');el.appendChild(petal)}}})})();